const payload = $input.first().json.body || $input.first().json;

const email = payload.email || '';
const name = payload.name || 'there';
const businessId = payload.businessId || 'bayflow';
const plan = payload.plan || 'starter';
const signupDate = new Date().toISOString();

if (!email) {
  throw new Error('Missing required field: email');
}

return [{
  json: {
    email,
    name,
    businessId,
    plan,
    signupDate
  }
}];

const { name } = $input.first().json;

const html = `
