const template = templates[emailToSend];

if (!template) {
  return [{ json: { ...user, _skip: true, reason: 'Unknown email template: ' + emailToSend } }];
}

return [{
  json: {
    ...user,
    emailSubject: template.subject,
    emailHtml: template.html
  }
}];

const user = $('Build Drip Email Template').first().json;
const resendResponse = $input.first().json;
const sent = !!(resendResponse.id);

if (!sent) {
  return [{ json: { ...user, sendFailed: true, error: resendResponse.error || 'Unknown error' } }];
}

const updatedSent = [...(user.previouslySent || []), user.emailToSend];

return [{
  json: {
    id: user.id,
    emailToSend: user.emailToSend,
    email: user.email,
    updatedSent,
    sendFailed: false
  }
}];
